import sys

def main():
    data = sys.stdin.read().split()
    idx = 0
    n = int(data[idx]); m = int(data[idx+1]); q = int(data[idx+2]); idx += 3

    grid = [[False]*(m+2) for _ in range(n+2)]
    h = [[0]*(m+2) for _ in range(n+2)]
    v = [[0]*(m+2) for _ in range(n+2)]

    def compute_h(i, j):
        if grid[i][j]: return 0
        if j+1 <= m and not grid[i][j+1]: return 1 + v[i][j+1]
        return 1

    def compute_v(i, j):
        if grid[i][j]: return 0
        if i+1 <= n and not grid[i+1][j]: return 1 + h[i+1][j]
        return 1

    total = 0
    for i in range(1, n+1):
        for j in range(m, 0, -1):
            h[i][j] = compute_h(i, j)
    for i in range(n, 0, -1):
        for j in range(1, m+1):
            v[i][j] = compute_v(i, j)

    for i in range(1, n+1):
        for j in range(1, m+1):
            if not grid[i][j]:
                total += h[i][j] + v[i][j] - 1

    results = []
    for _ in range(q):
        x = int(data[idx]); y = int(data[idx+1]); idx += 2

        # Collect affected cells: diagonal going up-left from (x,y)
        affected = []
        ci, cj = x, y
        while 1 <= ci <= n and 1 <= cj <= m:
            affected.append((ci, cj))
            ci -= 1; cj -= 1

        # Remove old contributions
        for (i, j) in affected:
            if not grid[i][j]:
                total -= h[i][j] + v[i][j] - 1

        # Flip
        grid[x][y] = not grid[x][y]

        # Recompute h and v for affected cells (bottom-right to top-left)
        for (i, j) in reversed(affected):
            pass
        for (i, j) in affected:
            h[i][j] = compute_h(i, j)
            v[i][j] = compute_v(i, j)
        # Need to recompute in correct order: h[i][j] depends on v[i][j+1], v[i][j] depends on h[i+1][j]
        # affected is top-left to bottom... no, we go up-left so affected[0]=(x,y), affected[-1]=top-left
        for (i, j) in reversed(affected):
            h[i][j] = compute_h(i, j)
            v[i][j] = compute_v(i, j)

        for (i, j) in affected:
            if not grid[i][j]:
                total += h[i][j] + v[i][j] - 1

        results.append(total)

    print('\n'.join(map(str, results)))

main()

